import { db } from '@/lib/db';
import { NextResponse } from 'next/server';

export async function GET() {
  try {
    const today = new Date();
    const dd = String(today.getDate()).padStart(2, '0');
    const mm = String(today.getMonth() + 1).padStart(2, '0');
    const yyyy = today.getFullYear();
    const todayStr = `${dd}/${mm}/${yyyy}`;

    const totalEmployees = await db.employee.count();

    const todayAttendance = await db.attendance.count({
      where: { date: todayStr },
    });

    const pendingRequests = await db.request.count({
      where: { status: 'pending' },
    });

    const activeTravel = await db.travelDeal.count({
      where: { status: { in: ['upcoming', 'in_progress'] } },
    });

    const presentCount = await db.attendance.count({
      where: { date: todayStr, status: 'present' },
    });

    const absentCount = await db.attendance.count({
      where: { date: todayStr, status: 'absent' },
    });

    // Late employees for today
    const lateAttendance = await db.attendance.findMany({
      where: { date: todayStr, status: 'late' },
      include: { employee: { select: { name: true } } },
      take: 20,
    });

    const lateEmployees = lateAttendance.map((a) => ({
      ...a,
      employeeName: a.employee.name,
    }));

    // Upcoming travel with all statuses
    const upcomingTravel = await db.travelDeal.findMany({
      where: { status: { in: ['upcoming', 'in_progress'] } },
      include: { employee: { select: { name: true } } },
      orderBy: { departureDate: 'asc' },
      take: 20,
    });

    const upcomingTravelWithName = upcomingTravel.map((t) => ({
      ...t,
      employeeName: t.employee.name,
    }));

    // Pending requests with details
    const pendingRequestsDetails = await db.request.findMany({
      where: { status: 'pending' },
      include: { employee: { select: { name: true } } },
      orderBy: { createdAt: 'desc' },
      take: 20,
    });

    const pendingRequestsWithName = pendingRequestsDetails.map((r) => ({
      ...r,
      employeeName: r.employee.name,
    }));

    // Employees grouped by department
    const allEmployees = await db.employee.findMany({
      select: { id: true, department: true, name: true },
    });

    const deptMap: Record<string, { name: string; count: number; employees: { name: string; id: string }[] }> = {};
    for (const emp of allEmployees) {
      const dept = emp.department || 'بدون قسم';
      if (!deptMap[dept]) {
        deptMap[dept] = { name: dept, count: 0, employees: [] };
      }
      deptMap[dept].count += 1;
      deptMap[dept].employees.push({ name: emp.name, id: emp.id });
    }
    const departments = Object.values(deptMap);

    // Booking data summary: count missing items per category
    const travelDeals = await db.travelDeal.findMany({
      where: { status: { in: ['upcoming', 'in_progress'] } },
    });

    const bookingSummary = {
      missingFlights: travelDeals.filter((t) => !t.hasFlight).length,
      missingHotels: travelDeals.filter((t) => !t.hasHotel).length,
      missingVisas: travelDeals.filter((t) => !t.hasVisa).length,
      missingTours: travelDeals.filter((t) => !t.hasTours).length,
      missingTransportation: travelDeals.filter((t) => !t.hasTransportation).length,
      totalBookings: travelDeals.length,
    };

    return NextResponse.json({
      totalEmployees,
      todayAttendance,
      pendingRequests,
      activeTravel,
      lateEmployees,
      upcomingTravel: upcomingTravelWithName,
      presentCount,
      absentCount,
      pendingRequestsDetails: pendingRequestsWithName,
      departments,
      bookingSummary,
    });
  } catch (error) {
    console.error('Home stats error:', error);
    return NextResponse.json(
      {
        totalEmployees: 0,
        todayAttendance: 0,
        pendingRequests: 0,
        activeTravel: 0,
        lateEmployees: [],
        upcomingTravel: [],
        presentCount: 0,
        absentCount: 0,
        pendingRequestsDetails: [],
        departments: [],
        bookingSummary: {
          missingFlights: 0,
          missingHotels: 0,
          missingVisas: 0,
          missingTours: 0,
          missingTransportation: 0,
          totalBookings: 0,
        },
      },
      { status: 200 }
    );
  }
}
